const payload = $json.payload;
let encodedData = "";

// Handle multipart messages
if (payload?.parts && payload.parts.length > 0) {
  // Try to find the HTML part
  const htmlPart = payload.parts.find(p => p.mimeType === "text/html");
  if (htmlPart?.body?.data) {
    encodedData = htmlPart.body.data;
  } else {
    // Fallback: plain text part
    const textPart = payload.parts.find(p => p.mimeType === "text/plain");
    if (textPart?.body?.data) {
      encodedData = textPart.body.data;
    }
  }
} else if (payload?.body?.data) {
  // Single-part messages
  encodedData = payload.body.data;
}

if (!encodedData) {
  return [{ json: { clean_text: "No email body found", raw: $json } }];
}

const decoded = Buffer.from(encodedData, "base64").toString("utf8");

// Clean the HTML
const cleanText = decoded
  .replace(/<style[\s\S]*?<\/style>/gi, "")
  .replace(/<script[\s\S]*?<\/script>/gi, "")
  .replace(/<[^>]+>/g, " ")
  .replace(/\s+/g, " ")
  .trim();

return [{ json: { clean_text: cleanText } }];

const labelMap = {
  "Notification": "Label_1414736328307638166",
  "Career": "Label_8103602173706276838",
  "Financial": "Label_1050924439689246211",
  "Meeting/Calender": "Label_1853905343760899982",
  "Personal": "Label_7799327710548104633",
  "Promotion": "Label_1521431043293045852",
  "Action Required": "Label_8828540256881400719",
  "Work": "Label_5722015042630001160",
  "Other": "Label_95103918350141184",
}; 



// Read input fields
const category = $json.category || "Notification";
const summary = $json.summary || "No summary provided.";

// Get label ID from map
const labelId = labelMap[category] || labelMap["Notification"];

// Choose emoji for better readability
let emoji = "📝";
switch (category) {
  case "Notification":
    emoji = "📩";
    break;
  case "Career":
    emoji = "💼";
    break;
  case "Financial":
    emoji = "💰";
    break;
  case "Meeting/Calender":
    emoji = "📅";
    break;
  case "Personal":
    emoji = "🏠";
    break;
  case "Promotion":
    emoji = "🎉";
    break;
  case "Action Required":
    emoji = "⚠️";
    break;
  case "Work":
    emoji = "🧑‍💻";
    break;
  default:
    emoji = "📝";
}

// Combine both category and label for output
const combinedMessage = `${emoji} [${category}] ${summary}`;

return [
  {
    json: {
      category,
      label_id: labelId,
      combined_message: combinedMessage,
      timestamp: new Date().toISOString()
    }
  }
];
